/**
 * Notification model types for the event-driven notification system.
 *
 * Architecture: All notifications flow through the EventBus. The NotificationService
 * subscribes to domain events, builds NotificationPayload objects, and delegates
 * delivery to registered NotificationAdapter implementations.
 *
 * Constraints:
 * - All delivery channels must implement the NotificationAdapter interface.
 * - NotificationType must be extended when new notification categories are added.
 * - NotificationChannel must be extended when new delivery mechanisms are added.
 */

/**
 * Categories of notifications the system can send.
 * Extend this union type when adding new notification categories.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_updated';

/**
 * Delivery channels for notifications.
 * Each channel has a corresponding NotificationAdapter implementation.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in_app' | 'sms';

/**
 * The payload passed to adapters for delivery.
 * This is the canonical shape that all adapters receive.
 */
export interface NotificationPayload {
  /** Unique notification ID */
  id: string;
  /** What kind of notification this is */
  type: NotificationType;
  /** Which channel to deliver through */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Notification subject/title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Optional structured metadata for adapter-specific needs */
  metadata?: Record<string, unknown>;
  /** When the notification was created */
  createdAt: Date;
}

/**
 * Result of a notification delivery attempt.
 */
export interface NotificationResult {
  /** The notification that was sent */
  notificationId: string;
  /** The channel it was delivered through */
  channel: NotificationChannel;
  /** Whether delivery succeeded */
  success: boolean;
  /** Error message if delivery failed */
  error?: string;
  /** When delivery was attempted */
  deliveredAt: Date;
}

/**
 * Interface that all notification delivery adapters must implement.
 *
 * To add a new notification channel:
 * 1. Add the channel name to the NotificationChannel type above.
 * 2. Create an adapter class implementing this interface in src/adapters/.
 * 3. Register it with NotificationService via registerAdapter().
 */
export interface NotificationAdapter {
  /** Which channel this adapter handles */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must return a NotificationResult indicating success/failure.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel.
 * Currently a stub that logs sends in-memory — replace the send()
 * implementation with a real email provider (SendGrid, SES, SMTP, etc.)
 * when ready for production.
 *
 * Architecture constraint: All adapters must implement NotificationAdapter
 * and be registered with NotificationService via registerAdapter().
 */

import type {
  NotificationAdapter,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Default sender address */
  from: string;
  /** Optional reply-to address */
  replyTo?: string;
}

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: Array<{ payload: NotificationPayload; config: EmailConfig }> = [];

  constructor(private config: EmailConfig) {}

  /**
   * Send a notification via email.
   *
   * Stub implementation: stores the email in memory and returns success.
   * Replace with real email provider integration for production use.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending email to ${payload.recipient}: "${payload.subject}"`,
    );

    this.sentEmails.push({ payload, config: this.config });

    return {
      notificationId: payload.id,
      channel: 'email',
      success: true,
      deliveredAt: new Date(),
    };
  }

  /**
   * Get all emails sent through this adapter. Useful for testing.
   */
  getSentEmails(): Array<{ payload: NotificationPayload; config: EmailConfig }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * Architecture: Event-driven via EventBus exclusively.
 * - Subscribes to domain events (order:created, order:status-changed, user:created, etc.)
 * - Converts events into NotificationPayload objects
 * - Delegates delivery to registered NotificationAdapter implementations
 *
 * Constraints:
 * - All notification triggers must come through EventBus events.
 * - All delivery channels must implement the NotificationAdapter interface.
 * - Register adapters via registerAdapter() before emitting events.
 *
 * Depends on:
 * - EventBus (event system) for receiving all domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../events/event-types.js';
import type {
  NotificationAdapter,
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface Notification {
  id: string;
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  sentAt: Date;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private results: NotificationResult[] = [];

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is supported — later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to all domain events that trigger notifications.
   * All notification triggers come through EventBus — no other mechanism.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });
  }

  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.sendNotification({
      type: 'order_confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    await this.sendNotification({
      type: 'order_status_update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    this.logger.info(`Sending welcome notification for user ${event.user.id}`);

    await this.sendNotification({
      type: 'welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: `Welcome to TaskFlow Pro!`,
      body: `Hi ${event.user.name}, your account has been created.`,
    });
  }

  /**
   * Send a notification through the appropriate adapter.
   * If no adapter is registered for the channel, the notification is still
   * recorded (for testing/audit) but no delivery is attempted.
   */
  private async sendNotification(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    metadata?: Record<string, unknown>;
  }): Promise<void> {
    const id = generateNotificationId();
    const now = new Date();

    const notification: Notification = {
      id,
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      sentAt: now,
    };
    this.notifications.push(notification);

    const adapter = this.adapters.get(params.channel);
    if (adapter) {
      const payload: NotificationPayload = {
        id,
        type: params.type,
        channel: params.channel,
        recipient: params.recipient,
        subject: params.subject,
        body: params.body,
        metadata: params.metadata,
        createdAt: now,
      };

      const result = await adapter.send(payload);
      this.results.push(result);
      this.logger.info(`Notification ${id} delivered via ${params.channel}: success=${result.success}`);
    } else {
      this.logger.info(`Notification ${id} recorded (no adapter for channel: ${params.channel})`);
    }
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Get delivery results from adapters.
   */
  getResults(): NotificationResult[] {
    return [...this.results];
  }

  /**
   * Clear all notifications and results (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
    this.results = [];
  }
}

